/*
 * 		자바=> 모든 소스는 클래스 안에 첨부
 * 		   => JVM이 가장 먼저 실행하는 부분 => main (진입점)
 * 		이미 만들어진 클래스 읽기 
 * 		------------------- 개발자 / java 제공
 * 		import 
 * 		=> 미국식 => 변경해서 사용
 * 		------------------- 오버라이딩 
 * 		package
 * 		import
 * 		public class ClassName{
 * 			public static void main(String[] args) { ->static public이라써도됨
		// TODO Auto-generated method stub
		}
   오류: 자바_시작 클래스에서 기본 메소드가 static이(가) 아닙니다. 다음 형식으로 기본 메소드를 정의하십시오.
   public static void main(String[] args)

 * 		public class ClassName{
 * 			public static void main(String[] a) { ->static public이라써도됨
		// TODO Auto-generated method stub
		}
 * 	}
 */
public class 자바_시작 {

	static public void main(String[] a) {
		// TODO Auto-generated method stub
		System.out.println("Hello Java");

	}

}
